var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"라미아라는 여자가 있습니다.","JPN":"ラミアという女がいました。","ENG":"There is a woman named Lamia.","TWN":"有個叫拉米亞的女人。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"사람 운명을 바꿔준다는 언더그라운드의 유명한 점쟁이.","JPN":"人の運命を変えてくれるという、アンダーグラウンドで有名な占い師。","ENG":"She is a famous fortune-teller in the Underground, known for altering people's fates.","TWN":"她是G1出了名的占卜師，能改變一個人的命運。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 그 유명세와 달리, 어디에서 지내는지 어디로 가야 만날 수 있는지는 아무도 모릅니다.","JPN":"でも、あれほど有名なのにどこに暮らしているのか、どこで会えるのかは誰も知りません。","ENG":"But despite her popularity, no one knows where she lives or where to meet her.","TWN":"但不同於她的名氣，沒人知道她住在哪裡，也不知道該去哪裡找她。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"항간에선 그녀가 좋은 술이 있는 술집에 자주 들른다고 하더군요.","JPN":"巷では彼女がいいお酒のあるバーによく出入りしていると言われています。","ENG":"There's a rumor that she often visits bars serving high-quality alcohol.","TWN":"聽說她常在有好酒的酒吧出沒。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"그래서 가게들도 저마다 들이는 술의 품질을 올리기 위해 노력한답니다.","JPN":"それでお店もお酒の品質を上げるために頑張っています。","ENG":"And that's why all the bars are doing their best to improve the quality of their drinks.","TWN":"所以各家店都在努力提升酒的品質。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"그 여자가 나타났다는 얘기만으로도 가게에 찾아오는 손님이 몰려서 경쟁력이 생길 정도니까요.","JPN":"あの女が現われたという話だけでも、店を訪ねるお客が多すぎて競争力を得るくらいですから。","ENG":"Just hearing that she had appeared in some bar is enough to attract customers.","TWN":"光是聽說她曾光顧，客人就會蜂擁而至，讓那間店生意興隆。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"저 사람. 신고라도 해야 하는 거 아냐?","JPN":"あの人、通報でもした方がいいんじゃないか？","ENG":"Don't you think we should report him to the police?","TWN":"那個人……是不是該報警啊？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"피를 엄청 흘리고 있는데… 괜찮은 건가?","JPN":"めちゃくちゃ血が流れてるんだけど……大丈夫なのかな？","ENG":"He's bleeding a lot... Do you think he's okay?","TWN":"他流了好多血……真的沒事嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"어머, 피범벅이 돼서 혼자 술을 마시는 남자라니. 너무 낭만적이잖아?","JPN":"あら、血まみれで1人でお酒を飲む男だなんて。とてもロマンチックね。","ENG":"Oh, dear. A bloodied man drinking all by himself? How romantic it is.","TWN":"哎呀，全身是血卻一個人喝酒的男人，太浪漫了吧？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"일 없으니 꺼져.","JPN":"用はない、失せろ。","ENG":"It's none of your business, so piss off.","TWN":"沒事就滾。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"아하하, 귀엽네. 다친 새끼늑대가 으르렁대는 것 같아.","JPN":"あはは、可愛いわ。怪我したオオカミの子どもが唸ってるみたい。","ENG":"Ah hah hah, how cute. You're like a wounded wolf cub, growling at others.","TWN":"哈哈，好可愛，像受傷的小狼在低吼呢。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"누구 말상대나 하러 온 거 아니니 좋게 말로 할 때 꺼지라고.","JPN":"誰かと話すために来ているわけでない。手を出す前に失せろって言っているんだ。","ENG":"I'm not here to chit chat, so leave me alone when I ask nicely.","TWN":"我不是來找人聊天的，趁我好好說話時快滾。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"알았어. 얌전히 옆자리에서 술만 마실 테니까.","JPN":"わかったわ。大人しく隣でお酒だけ飲むから。","ENG":"All right. Then I'll just silently drink beside you.","TWN":"好好好，我就安靜坐在旁邊喝酒。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"에잇.","JPN":"えいっ。","ENG":"Hmp!","TWN":"喂。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"큭…?! 뭐하는 짓이야!","JPN":"くっ……！？　何をしやがる！","ENG":"Kgh...?! What the hell was that for?!","TWN":"嗚……？！你在幹什麼！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"상처 좀 소독했어. 이대로는 술이 아니라 피비린내에 취해버릴 테니까.","JPN":"ちょっと傷の消毒ね。このままだとお酒じゃなくて血の匂いで酔いそうだったから。","ENG":"I disinfected your wound. Because I feel like I'll get drunk off the stench of blood rather than booze at this rate.","TWN":"幫你消毒傷口而已。再這樣下去，你就不是醉酒，而是醉在血腥味了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"어때? 술로 아픔을 잊는 것보다 훨씬 효율적이지?","JPN":"どう？　お酒で苦痛を忘れるよりはずっと効率的でしょう？","ENG":"How is it? It's way more effective than drinking your pain away, isn't it?","TWN":"怎樣？比起用酒忘記痛苦更有效率吧？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"……치유능력인가? 그런 류의 카운터는 드물다고 들었는데.","JPN":"……治癒能力か？　そんな類のカウンターは少ないと聞いたんだが。","ENG":"...A healing ability? I heard Counters with those kinds of abilities are hard to find.","TWN":"……這是治癒能力嗎？這類的處置方式很少見。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"마음에 들어? 치유만 할 수 있는 건 아니지만 말이야.","JPN":"気に入った？　他にもできることは色々あるけどね。","ENG":"Do you like it? And it's not just healing that I can do, you know.","TWN":"你喜歡嗎？我可不只會治療喔。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"괜한 오지랖이군. 자원봉사라도 다니나?","JPN":"余計なお世話だ。ボランティアでもしてるのか？","ENG":"Aren't you nosy? Are you a volunteer for something or what?","TWN":"少管閒事。你是做義工的嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"딱히 공짜로 해준다곤 안 했어.","JPN":"別にただでやってあげるとか言ってないわよ？","ENG":"I didn't say it was for free.","TWN":"我可沒說免費哦。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"돈 없다. 뜯어낼 목적이라면 상대 잘못 골랐어.","JPN":"お金はない。巻き上げるつもりなら相手が悪かったな。","ENG":"I got no money. If you're trying to rip someone off, you chose the wrong guy.","TWN":"我沒錢。要敲詐的話，你找錯人了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"그래? 손에 피 묻히고 술 마시러 다니는 사람은 보통 돈이 많던데.","JPN":"そう？　血まみれの手で飲みに来る人は普通、お金をたくさん持ってたわよ。","ENG":"Oh, really? I thought people who drink with blood on their hands are usually loaded.","TWN":"是嗎？手上沾滿血還來喝酒的人，通常都很有錢。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"영화를 너무 많이 봤군.","JPN":"映画の見すぎだ。","ENG":"Guess you've been watching too many movies.","TWN":"你電影看太多了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"좋아. 돈은 안 받을게. 대신 얘기나 좀 해줘.","JPN":"いいわ。お金は取らない。その代わりに話して。","ENG":"All right. I won't take your money then. But tell me a story instead.","TWN":"好吧，我不收錢。你陪我聊聊天就好。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"어쩌다 그렇게 다쳐서 여기까지 오게 된 건지.","JPN":"どうしてそんな怪我をして、ここまで来たのか。","ENG":"How did you end up here with all those wounds?","TWN":"像是你怎麼會傷成這樣還跑來這裡。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"…사람을 해쳤어. 그런 얘기를 가십거리로 쓰고 싶진 않아.","JPN":"……人を害した。そんな話をゴシップにしたくはない。","ENG":"...I hurt a person. But I don't want to gossip about something like that.","TWN":"……我傷害了一個人。我不想把那種事當成八卦話題。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"처음이구나? 사람을 해쳐본 건.","JPN":"初めてなんだ？　人を傷つけたの。","ENG":"Is it your first time? Hurting another person?","TWN":"這是第一次吧？傷害人的事。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"하지만, 아직 그걸 즐기는 성격은 못되는 모양이네?","JPN":"でも、まだそれを楽しめる性格じゃないんだね。","ENG":"But it seems like you didn't really enjoy it.","TWN":"但你看起來還不會享受那種感覺？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"웃기지 마. 돌이키긴 늦었지만… 이번 한 번은 어쩔 수 없었을 뿐이야.","JPN":"ふざけるな。取り返しはつかないが……今度は仕方がなかったんだ。","ENG":"Don't be ridiculous. It's too late to turn back now... but there was nothing I could do this time.","TWN":"別胡說。雖然已經回不了頭了……但這次只是逼不得已。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"흐음. 어쩔 수 없는 일이구나.","JPN":"ふーん。仕方のないことだったんだ。","ENG":"Hmm... Nothing you could do, eh?","TWN":"嗯～逼不得已啊。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"하지만 이상한 걸? 내가 보기에 당신은 앞으로도 많은 피를 묻히게 될 것 같은데.","JPN":"でもおかしいわね。アタシが見るには、アナタはこれからもたくさん手を血に染めることになりそうだけど。","ENG":"That's odd. Because in my eyes, it looks like you'll be drenched in a lot of blood in the future.","TWN":"不過，真奇怪？在我看來，你以後還會沾上更多血。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"당신이 남자였다면 이미 한 번 더 피를 봤겠지. 시비를 걸고 싶은 거라면 제발 다른 상대를 찾아.","JPN":"お前が男だったらもう一度血に染まっていたはずだ。喧嘩を売りたいなら他をあたれ。","ENG":"If you were also a man, I would've already. If you're here to pick a fight, find someone else.","TWN":"你要是男人，現在大概已經又見血了。想找麻煩的話去找別人。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"너, 경찰이지?","JPN":"アナタ、警察でしょう？","ENG":"Hey, you're a cop, aren't ya?","TWN":"你是警察吧？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"…내 뒷조사라도 한 거냐?","JPN":"……俺の調査でもしたのか？","ENG":"...Did you have someone do a background check on me?","TWN":"……你調查過我？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"감이야. 술집에서 여러 손님을 만나다 보면, 인상만 봐도 어렴풋이 알 수 있거든.","JPN":"感よ。バーで色んなお客さんに出会っていると、印象だけでも薄らとわかるわ。","ENG":"It's just a feeling I got. Once you've met a lot of people in bars, you can tell what they do based on their impressions.","TWN":"直覺而已。在酒吧見過的人多了，看表情就能猜個大概。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"못된 범법자들 때문에 다친 거야?","JPN":"悪い犯罪者たちのせいで怪我したの？","ENG":"Were you hurt because of criminals?","TWN":"你是被那些可惡的罪犯害的？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"멍청한 친구놈 뒷바라지하다 실수로 미끄러졌을 뿐이야.","JPN":"バカ友だちの後始末でうっかり滑っただけど。","ENG":"I accidentally slipped while I was helping out an idiot friend.","TWN":"我只是替一個蠢朋友收拾爛攤子時不小心失手而已。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"실수로 사람을 치다니, 칠칠맞은 경찰이네. 나 같은 선량한 시민이 발 뻗고 잘 수 있을까 몰라.","JPN":"うっかり人に害をなすなんて、だらしない警察ね。アタシみたいな善良な市民は安心して眠れるのかしら。","ENG":"If you accidentally hurt someone, you must not be a very good cop. How can an innocent citizen like me rest at ease knowing this, hmm?","TWN":"不小心傷了人，真是個粗心的警察。像我這種善良市民能安心睡覺嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"흥, 그런 걱정이라면 마. 일은 관둘 거니까.","JPN":"ふん、そんな心配ならいらない。仕事はやめるつもりだ。","ENG":"Hmph. You don't have to worry about that. I'm gonna quit, anyway.","TWN":"哼，你放心，我會辭職的。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"백수라도 되려고?","JPN":"無職になるの？","ENG":"Willfully becoming unemployed?","TWN":"你打算當無業遊民？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"그건 당신이 알 바 아니지.","JPN":"それはお前の知ったことじゃないな。","ENG":"That's none of your business.","TWN":"那不關你的事吧。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"아하, 실수 한 번 저질렀다고 아예 범죄자로 전향하려는 거야?","JPN":"へえ、1度ミスしただけで、犯罪者に転向するの？","ENG":"A-ha, so you've decided to become a criminal just because you made one lousy mistake?","TWN":"啊哈，不過是犯了一次錯，你就打算乾脆當罪犯啦？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"적어도 범죄를 저질러 놓고 경찰일을 계속 할 정도로 뻔뻔하진 않거든.","JPN":"少なくとも犯罪を犯して警察の仕事を続けるほど図々しくはないんだよ。","ENG":"At least I'm not shameless enough to continue as a cop after committing a crime.","TWN":"至少我不會厚著臉皮，一邊犯罪一邊繼續當警察。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"친구놈이… 자기 패밀리에 내 자릴 알아봐주기로 했어. 거기서 새로 시작해야지.","JPN":"友だちが……自分のファミリーに俺を入れてくれようとしている。あそこで新しく始めるんだ。","ENG":"My friend... He said he'd find me a spot in his mafia family. I'll have to start over there.","TWN":"那傢伙……答應幫我在他的家族裡找個位子。我要在那裡重新開始。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"친구 때문에 범죄를 저지르고, 결국 그 친구 밑으로 들어가는 거야?","JPN":"友だちのせいで犯罪を犯して、結局はその友だちの部下になるの？","ENG":"So you committed a crime because of your friend, and now you're going to go work for him?","TWN":"你因為朋友犯了罪，最後還投靠他？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"패버리고 싶을 만큼 무모한 녀석이지만, 사업 수완 하나는 좋아서 말이지.","JPN":"殴りまくりたいほど無謀なやつだが、仕事の腕だけは確かでな。","ENG":"He's reckless, and stupid enough that I want to beat him up. But he's good at business.","TWN":"那傢伙魯莽到讓人想揍他一頓，但他做生意的手腕確實不錯。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"…열심히 해봐. 너 정도의 가능성이라면 뭘 해도 성공할 수 있을 테니까.","JPN":"……頑張ってね。アナタほどの可能性なら、何をしても成功できるはずだから。","ENG":"...Good luck. I think you'll be able to succeed in anything with your possibilities.","TWN":"……加油吧。以你的潛力，做什麼都能成功。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"망할. 내가 왜 이런 얘길 처음보는 여자한테 주절주절 떠들어대는지 모르겠군.","JPN":"くそ。どうして俺が初対面の女にこんな話をしているんだか。","ENG":"Dammit. I don't know why I'm even telling a woman I just met in a bar all this.","TWN":"該死，我怎麼會對第一次見面的女人說這麼多。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"괜찮아. 누구나 취하면 자기 속마음을 털어놓고 싶은 법이잖아?","JPN":"大丈夫よ。酔うと誰でも自分の心の中を話したくなるわけだしね。","ENG":"It's all right. People want to let out their true feelings when they're drunk.","TWN":"沒事，人喝醉了都會想說真心話啊？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"그리고 나, 술 깨면 아무것도 기억 못하는 타입이거든.","JPN":"それにアタシ、酔いが覚めると何も覚えていないタイプだわ。","ENG":"And I'm the type who can't remember a thing after waking up the next day.","TWN":"而且我啊，酒醒之後什麼都不記得了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"…차라리 나도 그랬으면 좋겠네.","JPN":"……俺もそうであってほしいな。","ENG":"...I wish I was like that.","TWN":"……真希望我也是那樣。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"후회하고 있어?","JPN":"後悔してる？","ENG":"Do you regret it?","TWN":"你後悔了？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"크큭, 후회하지. 한때 경찰을 꿈꿨던 내가 한심해질 정도로 말이야.","JPN":"ククッ、後悔するさ。かつて警察を夢見た俺が情けないほどに。","ENG":"Keke, of course. I regret it so much that I consider myself pathetic for ever dreaming of becoming a police officer.","TWN":"呵，是啊。這讓曾經想當警察的自己覺得很心寒。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"어차피 이렇게 될 거였으면 경찰이고 뭐고 처음부터 그 친구놈 따라가는 건데.","JPN":"どうせこうなるんだったら、警察も何も最初からあの友だちについて行くんだった。","ENG":"If I had known this was going to happen, I would have started working with my friend from the beginning.","TWN":"早知道會變成這樣，不如一開始就跟著那傢伙混了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"그 친구라는 사람… 너무 의지하지 않는 게 좋아.","JPN":"その友だちって人……あんまり頼らない方がいいわ。","ENG":"This friend of yours... I think it's best you don't rely on him too much.","TWN":"你最好別太依賴……那個朋友。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"믿고 있던 게 틀렸을 때의 충격은 생각보다 크거든.","JPN":"信じていた人に裏切られた時のショックは思ったよりひどいから。","ENG":"The shock of being betrayed by something or someone you trusted hits harder than you might think.","TWN":"一旦發現看錯了人，打擊會比想像中更大。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"흥, 쓸데없는 걱정이다. 의리 하난 확실한 녀석이라고.","JPN":"ふん、余計な心配だ。あいつは義理堅いやつなんだよ。","ENG":"Hmph. That's something I don't need to worry about. He's a straight-shooting loyal guy.","TWN":"哼，你擔心太多了，他是個很講義氣的傢伙。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"벌써 가려고?","JPN":"もう行くの？","ENG":"You're leaving already?","TWN":"你要走了？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"그래, 상처를 치료해준 답례가 술값 내주는 것뿐이라 미안하군.","JPN":"ああ。悪いな、傷を治療してくれたお礼が飲み代を払うだけになっちまって。","ENG":"Yeah. Sorry that all I can do is pay for your drinks for treating my wounds.","TWN":"嗯，抱歉，只能請你喝酒當作治療的回禮。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"어머, 정말? 그럼 부탁할게?","JPN":"あら、本当に？　じゃあ、頼むわね。","ENG":"Oh, really? Thanks!","TWN":"哎呀，真的嗎？那我就不客氣了？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"…계산서가 좀 이상한데. 단체 손님이라도 데려온 건가?","JPN":"……お会計がおかしいんだが。団体客でも連れてきたのか？","ENG":"...It looks like there's an error on the bill. Are you with a group or something?","TWN":"……帳單有點奇怪，你是帶了整團人來嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"내가 주량이 좀 센 편이거든.","JPN":"アタシ、お酒に強いの。","ENG":"I'm a bit of a heavy drinker.","TWN":"我酒量算好的啦。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"나 참, 그냥 아주 술집을 차리지 그래?","JPN":"ったく、いっそのこと、自分でバーを運営したらどうだ？","ENG":"Ugh, why don't you just run your own bar or something?","TWN":"真是的，還不如你自己開家酒吧算了？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"조만간 그렇게 하려고. 지금보다 형편이 좀 더 나아지면 말이야.","JPN":"そのうちそうするつもりよ。今よりは生活がましになったらね。","ENG":"I'm planning on it. Once my situation gets better, that is.","TWN":"如果我條件比現在好一點，我打算在近期開一間。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MATCHMAN_NPC_PAST_NULL","text":{"KOREA":"일이 잘 풀리고 나면, 다음 번엔 내가 당신 가게를 한 번 찾아가지.","JPN":"仕事がうまく行くと、今度は俺がお前の店を訪ねるとしよう。","ENG":"Once everything works out well, I'll come visit your bar some time.","TWN":"等事情都順利了，下次我會去你店裡找你。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"바이 바이-","JPN":"バイバーイ。","ENG":"Bye-bye.","TWN":"拜拜—"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"야망은 크고 정에는 약한 남자라… 저러면 보통 등에 칼 맞고 끝나던데.","JPN":"野望は大きくても人の情には弱い男、ねえ……あれは普通裏切られるんだけど。","ENG":"An ambitious, but warm-hearted man... Those types usually get a knife to their backs.","TWN":"野心很大，卻又太重感情的男人啊……這種人通常最後都會被捅一刀。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"역시 명함이라도 주고 보낼 걸 그랬나?","JPN":"やっぱり名刺でもあげた方がよかったのかしら？","ENG":"Maybe I should've given him my business card?","TWN":"剛剛是不是該給他一張名片比較好？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"라미아는 거짓말을 할 줄 모르는 상냥한 여자입니다.","JPN":"ラミアは嘘がつけない優しい女です。","ENG":"Lamia is a kind woman who doesn't know how to lie.","TWN":"拉米亞，是個不會說謊的溫柔女人。"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"굳이 거짓말을 하지 않아도, 인간들은 욕망이란 관성에 이끌려 제 발로 그녀를 찾아오니까요.","JPN":"あえて嘘をつかなくても、人間たちは欲望という惰性に引かれて自分の足で彼女を訪ねるのです。","ENG":"Even without her lying, humans' inertia of desire attracts people to come to her.","TWN":"就算不說謊，人類也會被慾望的慣性牽引，主動找上她。"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"narration","speaker":null,"text":{"KOREA":"맹목적인 욕망. 그 끝에 파멸이 기다린다는 걸 알더라도 인간들은 욕망을 포기하지 않습니다.","JPN":"盲目的な欲望。その果てに破滅が待っていると知っていながらも、人間たちは欲望を諦めません。","ENG":"Blind desire. Even knowing that destruction waits at the end, humans do not give up their desires.","TWN":"即使知道盲目的慾望盡頭是毀滅，人類依然不會放棄。"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"그건 오랜 시간이 흘러도 결코 변하지 않는 진실이죠.","JPN":"それは時間が過ぎても決して変わらない真実です。","ENG":"This is a truth that remains constant regardless of time.","TWN":"這是不管過了多久，都不會改變的真理。"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OWNER_NPC_NULL_NULL","text":{"KOREA":"커헉… 컥… 사, 살려주십쇼.","JPN":"がはっ……くっ……も、もう勘弁、勘弁してくだない。","ENG":"Kuh... Ugh... P-please, have mercy.","TWN":"咳咳……咳……救、救命……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L24_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"말해. 그 여잔 어디에 있지?","JPN":"話せ。あの女はどこだ？","ENG":"Talk. Where is she?","TWN":"說，那女人在哪？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OWNER_NPC_NULL_NULL","text":{"KOREA":"모릅니다. 정말 모릅니다… 저희 가게를 자주 찾는 건 사실이지만… 최근엔 온 적이 없습니다.","JPN":"わかりません。本当にわかりませんよ……確かにうちの店にはよく来るんですけど……最近は来たことがないんです。","ENG":"I don't know. I really don't... It is true that she frequents our bar, but... she hasn't visited recently.","TWN":"我不知道！我真的不知道……她確實常來我們店……但最近都沒有來。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"그래? 그럼 이 가게도 전부 불태워 없애버리면 그 여잘 훨씬 찾기 수월해지겠군.","JPN":"そうか？　じゃあこの店も全部燃やしてしまえば、あの女を探すことも楽になるだろうな。","ENG":"Oh, yeah? Then it'll make my job easier to find her after I burn this bar down to the ground.","TWN":"是嗎？那我把這家店燒了，應該會更快找到她吧。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"OWNER_NPC_NULL_NULL","text":{"KOREA":"안돼요! 부탁드립니다! 가게만은 제발!","JPN":"駄目です！　お願いします！　お店だけは、どうか！","ENG":"No! Please! Not my bar!","TWN":"不行！拜託你！請你放過我的店！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"그만둬.","JPN":"やめなさい。","ENG":"That’s enough.","TWN":"住手。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"오?","JPN":"お？","ENG":"Oh?","TWN":"哦？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"너였구나? 내가 좋아하는 단골 가게들만 전부 부수고 다닌다는 손님이.","JPN":"アナタだったのね。アタシのお気に入りのお店だけ、全部壊して回ってるお客さんって。","ENG":"So it's you. You're the one who has been going around destroying my favorite bars.","TWN":"原來是你啊，那個專砸我常去的店的客人。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"오랜만이군. 아가씨.","JPN":"久しぶりだな、お嬢さん。","ENG":"Long time no see, missy.","TWN":"好久不見了，小姐。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"아니, 라미아라고 불러드리면 되나?","JPN":"いや、ラミアと呼んだ方がいいか？","ENG":"Or should I call you, Lamia?","TWN":"不，該叫你拉米亞嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"용건만 말하자. 날 찾은 이유가 뭐니?","JPN":"用件だけ言って。アタシを探した理由は何かしら。","ENG":"What do you want? Why are you looking for me?","TWN":"有話直說吧。你找我有什麼事？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"당신의 그 신기한 재주를 부려서 날 평의회의 일원으로 만들어줘.","JPN":"お前のその不思議な能力で、俺を評議会の一員にしてくれ。","ENG":"I want you to use your magic to make me a member of the Council.","TWN":"用你那詭異的能力，讓我成為議會的一員。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"눈빛이 변했구나.","JPN":"目つきが変わったのね。","ENG":"Your eyes have changed.","TWN":"你的眼神變了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"그런가? 당신과 헤어진 뒤로 꽤 많은 일들이 있었거든.","JPN":"そうか？　お前と別れた後、結構いろんなことがあってな。","ENG":"Have they? I've been through a lot since we last met.","TWN":"是嗎？跟你道別後，發生了很多事。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"날 실컷 이용해먹고 버리려던 그 친구라는 버러지도 처리하고 말이지.","JPN":"俺を思いっきり利用して捨てようとしたあの友だちって虫けらも始末した。","ENG":"I even got rid of that friend who tried to use me and threw me away.","TWN":"我也把那個想利用完我就丟的垃圾朋友處理掉了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"가엾어라. 짐승에게 당하지 않기 위해 짐승이 되다니.","JPN":"可哀想に。獣にやられないために獣になるなんてね。","ENG":"Poor thing. So you became a monster to avoid becoming their prey.","TWN":"真可憐。為了不被野獸吃掉，自己變成野獸了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"피차 마찬가지 아닌가? 라미아도 나 같은 구제불능의 짐승들만 상대한다던데.","JPN":"それはお互い様じゃないか？　ラミアも俺みたいなダメ人間だけを相手してるらしいじゃないか。","ENG":"Aren't you the same? You've always dealt with helpless monsters like me, haven't you, Lamia?","TWN":"彼此彼此吧？聽說你專門跟像我這樣沒救的野獸打交道。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"넌… 다시 돌아갈 기회가 있어. 아직은 말이야.","JPN":"アナタは……取り返すチャンスがある。まだね。","ENG":"You... still have a chance to make things right. At least for now.","TWN":"你……還有回頭的機會。至少現在還有。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"지금이라도 손을 씻고 생활을 청산해. 그럼 업보에 짓이겨지는 일은 없을 거야.","JPN":"今でも足を洗ってそんな生活をやめなさい。そうしたら業に潰されることなんてないよ。","ENG":"Come clean from that life. Then, you won't be crushed by karma.","TWN":"現在就金盆洗手、重新生活，業報就不會壓垮你。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"으하하하!","JPN":"はははは！","ENG":"Mwa hah hah!","TWN":"哈哈哈哈！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L3_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"…그거 아나? 내가 아는 것들 중 가장 쓸모없는 게 바로 동정심이지.","JPN":"……知ってるか？　俺が知っている一番不要なのが同情心だ。","ENG":"...You know what? The most useless thing I know is sympathy.","TWN":"……你知道嗎？我見過最沒用的東西，就是同情心。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"얄팍한 합리화로 사람을 나약해지게 만들 뿐, 결국 변하는 건 아무것도 없어.","JPN":"薄っぺらな言い訳で人を弱くするだけ。結局は何も変わらない。","ENG":"It makes you weak through superficial justifications, and it changes nothing.","TWN":"只會用膚淺的合理化讓人軟弱，結果什麼都改變不了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"그래?","JPN":"そう？","ENG":"Is that so?","TWN":"是嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"그럼 대가가 없는 소원은 세상에 없다는 것도 알아?","JPN":"じゃあ、対価のない願い事はこの世にないってことも知ってるのかしら？","ENG":"Then you must also know that everything comes at a cost.","TWN":"那你也知道，這世上沒有不用付出代價的許願吧？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"크큭, 이제 말이 통하는군. 원하는 게 있으면 뭐든 대령할 테니 말만 하라고.","JPN":"ククッ、やっと話が通じるようになったな。欲しいものがあれば何なりと出すから、話せ。","ENG":"Keke, now we're talking. I'll give you whatever you want in return.","TWN":"呵，終於能溝通了。你想要什麼儘管說。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"그 대가가 결국 널 망가뜨리게 된다고 해도?","JPN":"その対価が結局アナタを壊すことになっても？","ENG":"Even if what I want will destroy you?","TWN":"就算代價會徹底毀掉你？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"고작 뒷돈 좀 받아먹었다고,","JPN":"お金が必要で、","ENG":"Just because I took some bribes","TWN":"你知道光是收點回扣、"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"뒷골목에서 인정 좀 받아보겠다고,","JPN":"裏社会で認められたくて、","ENG":"and wanted to get some street cred,","TWN":"想在後巷混出點名聲，"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"그렇게 날 죽이려고 든 형제가 몇이나 되는 줄 알아?","JPN":"そんな理由で俺を殺そうとした兄弟が何人だと思う？","ENG":"do you know how many members tried to kill me?","TWN":"就有多少兄弟想為了這種理由殺了我嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"다른 패밀리 놈들과 신경전이나 벌이면서 배신자를 숙청하는 일 같은 건 이제 지긋지긋하거든.","JPN":"他のファミリーのやつらと睨み合って、裏切り者を始末することなんざもうこりごりなんだよ。","ENG":"I'm sick of playing mind games with the other mafias and executing traitors.","TWN":"我早就對跟其他家族勾心鬥角、清理叛徒的戲碼感到厭倦。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"당장 이 엿 같은 상황을 내 뜻대로 바꿀 수만 있다면 리스크는 상관없어.","JPN":"今すぐこのクソみたいな状況を俺の望むままに変えられるんだったら対価なんて構わない。","ENG":"If I can get out of this damn situation, I don't care what the risks are.","TWN":"只要能把這該死的現狀變成我想要的樣子，冒點風險無所謂。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GREMORY_BAR_PAST_NULL","text":{"KOREA":"그래, 그런 각오라면 어떤 대가를 마주하게 되더라도… 후회하진 않겠네.","JPN":"そう、そういう覚悟ならどんな対価を目の前にするとしても……後悔しなさそうね。","ENG":"Very well. I see you won't regret... whatever price you'll have to pay for your choices.","TWN":"好吧。既然你有這種覺悟，那不管付出什麼代價……你也不會後悔。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_PAST_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"찬장에서 가장 독한 걸로 가져왔어.","JPN":"棚でもっとも強いもので持ってきたわ。","ENG":"I brought the strongest one from the cupboard.","TWN":"我從櫥櫃裡拿了最烈的酒出來。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"무슨 술을 좋아했는지 기억이 안 나서 말이야.","JPN":"どんなお酒が好きだったのか覚えていなくて。","ENG":"I can't seem to remember what you liked to drink.","TWN":"我忘了你喜歡喝什麼。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"…나쁜 기억도, 좋은 기억도, 정신없이 취해버리면 다 잊어버리거든.","JPN":"……悪い記憶も、いい記憶も、べろべろに酔っちゃうと全部忘れてしまう。","ENG":"...You'll forget about all your bad and good memories once you're completely drunk.","TWN":"……不管是好的或壞的記憶，只要醉到不行，就會忘得一乾二淨。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"네가 바꿔 놓은 인과는 분명 우리 모두를…","JPN":"アナタが変えた因果はきっとアタシたちみんなを……","ENG":"All the causality you've changed will definitely make all of us–","TWN":"你改變的因果，確實會把我們所有人……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"…아니, 이런 입에 발린 소리 따위 아무래도 좋으려나?","JPN":"……いや、こんな綺麗事はどうでもいいかしらね。","ENG":"...No, I guess sugarcoating it won't be of any use to you.","TWN":"……算了，也沒必要說這種場面話。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"계약은 끝났어. 넌 자유야.","JPN":"契約は終わりだわ。アナタは自由になったの。","ENG":"The contract's over. You're free now.","TWN":"契約結束了。你自由了。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"이제 그만 편히 취하도록 해.","JPN":"もうお休みなさい。","ENG":"All that's left for you is to rest in peace.","TWN":"好好醉一場吧。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"narration","speaker":null,"text":{"KOREA":"라미아는 유명한 예언가였습니다.","JPN":"ラミアは有名な預言者でした。","ENG":"Lamia was a famous prophet.","TWN":"拉米亞，曾是名震一時的預言家。"},"stage":{"bg":"black","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"narration","speaker":null,"text":{"KOREA":"그녀의 존재는 한때 암흑가에 큰 변화를 불러오며, 소문이 헛것이 아님을 증명했습니다.","JPN":"彼女の存在はかつて暗黒街に大きな変化を引き寄せ、その噂が本当であることを証明しました。","ENG":"Her presence had brought about great change in the underworld, proving that the rumors were true.","TWN":"她的存在一度為黑暗世界帶來巨大變化，也證明傳聞並非空穴來風。"},"stage":{"bg":"black","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 그녀가 자취를 감춘 뒤로도, 여전히 많은 것이 베일에 싸여 있습니다.","JPN":"だけど彼女が姿を暗ました後にも、相変わらずたくさんのことが謎に包まれています。","ENG":"But even after she went into hiding, a lot is still shrouded in mystery.","TWN":"但在她消失之後，仍有太多事情籠罩在迷霧之中。"},"stage":{"bg":"black","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"narration","speaker":null,"text":{"KOREA":"그녀가 어떻게 그런 능력을 갖고 있었는지,","JPN":"彼女がどうやってそんな能力を持っていたのか、","ENG":"No one knows how she was able to possess such power,","TWN":"她的能力從何而來，"},"stage":{"bg":"black","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"그리고 암흑가의 거물들은 대체 어떤 대가를 그녀에게 지불했는지,","JPN":"そして暗黒街の大物たちは彼女にいったいどんな対価を払ったのか、","ENG":"what the lords of the underworld paid her,","TWN":"那些黑道巨頭究竟付出了什麼代價，"},"stage":{"bg":"black","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"무엇을 목적으로 그녀가 그런 짓을 벌였는지, 우리는 모릅니다.","JPN":"何が目的で彼女がそんなことをしたのか、私たちは知りません。","ENG":"or even with what purpose she acted.","TWN":"她又是為了什麼目的行動，"},"stage":{"bg":"black","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"진실은 당사자만이 알고 있겠죠.","JPN":"真実は本人のみぞ知っているでしょう。","ENG":"Only she knows the truth.","TWN":"只有當事人知道這些真相吧。"},"stage":{"bg":"black","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};